import java.util.*

fun solve(n: Long, edges: Array<Array<Long>>): Long {
    val adj = Array(n.toInt()) { mutableListOf<Array<Long>>() }
    for (edge in edges) {
        val u = edge[0]
        val v = edge[1]
        val s = edge[2]
        val e = edge[3]
        adj[u.toInt()].add(arrayOf(v, s, e))
    }

    val dist = LongArray(n.toInt()) { Long.MAX_VALUE }
    dist[0] = 0L

    val pq = PriorityQueue<Pair<Long, Long>> { a, b -> a.first.compareTo(b.first) }
    pq.add(Pair(0L, 0L))

    while (pq.isNotEmpty()) {
        val (currentTime, u) = pq.poll()
        if (u == n - 1) return currentTime
        if (currentTime > dist[u.toInt()]) continue
        for (edge in adj[u.toInt()]) {
            val v = edge[0]
            val s = edge[1]
            val e = edge[2]
            val earliestTime = Math.max(currentTime, s)
            if (earliestTime > e) continue
            val newTime = earliestTime + 1
            if (newTime < dist[v.toInt()]) {
                dist[v.toInt()] = newTime
                pq.add(Pair(newTime, v))
            }
        }
    }

    return -1
}
