class PriorityQueue {
    private val heap: MutableList<Array<Long>> = mutableListOf()
    fun push(value: Array<Long>) {
        heap.add(value)
        siftUp(heap.size - 1)
    }
    fun pop(): Array<Long>? {
        if (heap.isEmpty()) return null
        val top = heap[0]
        heap[0] = heap.last()
        heap.removeLast()
        siftDown(0)
        return top
    }
    private fun siftUp(index: Int) {
        while (index > 0) {
            val parent = (index - 1) / 2
            if (heap[parent][0] <= heap[index][0]) break
            swap(parent, index)
            index = parent
        }
    }
    private fun siftDown(index: Int) {
        var i = index
        val size = heap.size
        while (i < size) {
            val left = 2 * i + 1
            val right = 2 * i + 2
            var smallest = i
            if (left < size && heap[left][0] < heap[smallest][0]) smallest = left
            if (right < size && heap[right][0] < heap[smallest][0]) smallest = right
            if (smallest != i) {
                swap(i, smallest)
                i = smallest
            } else {
                break
            }
        }
    }
    private fun swap(i: Int, j: Int) {
        val temp = heap[i]
        heap[i] = heap[j]
        heap[j] = temp
    }
}

fun solve(n: Long, edges: Array<Array<Long>>): Long {
    val adj = Array(n.toInt()) { mutableListOf<Array<Long>>() }
