class PriorityQueue {
    private val heap: MutableList<Array<Long>> = mutableListOf()
    fun push(value: Array<Long>) {
        heap.add(value)
        siftUp(heap.size - 1)
    }
    fun pop(): Array<Long>? {
        if (heap.isEmpty()) return null
        val top = heap[0]
        heap[0] = heap.last()
        heap.removeLast()
        siftDown(0)
        return top
    }
    private fun siftUp(index: Int) {
        while (index > 0) {
            val parent = (index - 1) / 2
            if (heap[parent][0] <= heap[index][0]) break
            swap(parent, index)
            index = parent
        }
    }
    private fun siftDown(index: Int) {
        var i = index
        val size = heap.size
        while (i < size) {
            val left = 2 * i + 1
            val right = 2 * i + 2
            var smallest = i
            if (left < size && heap[left][0] < heap[smallest][0]) smallest = left
            if (right < size && heap[right][0] < heap[smallest][0]) smallest = right
            if (smallest != i) {
                swap(i, smallest)
                i = smallest
            } else {
                break
            }
        }
    }
    private fun swap(i: Int, j: Int) {
        val temp = heap[i]
        heap[i] = heap[j]
        heap[j] = temp
    }
}

fun solve(n: Long, edges: Array<Array<Long>>): Long {
    val adj = Array(n.toInt()) { mutableListOf<Array<Long>>() }
    for (edge in edges) {
        val u = edge[0].toInt()
        val v = edge[1].toInt()
        val s = edge[2]
        val e = edge[3]
        adj[u].add(arrayOf(v.toLong(), s, e))
    }

    val dist = LongArray(n.toInt()) { Long.MAX_VALUE }
    dist[0] = 0L

    val pq = PriorityQueue()
    pq.push(arrayOf(0L, 0L))

    while (pq.heap.isNotEmpty()) {
        val popped = pq.pop()
        if (popped == null) break
        val currentTime = popped[0]
        val u = popped[1].toInt()
        if (u == n - 1) return currentTime
        if (currentTime > dist[u]) continue
        for (edge in adj[u]) {
            val v = edge[0].toInt()
            val s = edge[1]
            val e = edge[2]
            val earliest = Math.max(currentTime, s)
            if (earliest > e) continue
            val newTime = earliest + 1
            if (newTime < dist[v]) {
                dist[v] = newTime
                pq.push(arrayOf(newTime, v.toLong()))
            }
        }
    }

    return -1L
}
