```javascript
function solve(n, edges) {
  const adj = new Array(n).fill().map(() => []);
  for (const [u, v, s, e] of edges) {
    adj[u].push([v, s, e]);
  }

  const dist = new Array(n).fill(Infinity);
  dist[0] = 0;

  class PriorityQueue {
    constructor() {
      this.heap = [];
    }
    push(value) {
      this.heap.push(value);
      this.siftUp(this.heap.length - 1);
    }
    pop() {
      if (this.heap.length === 0) return undefined;
      const top = this.heap[0];
      this.heap[0] = this.heap.pop();
      this.siftDown(0);
      return top;
    }
    siftUp(index) {
      while (index > 0) {
        const parent = Math.floor((index - 1) / 2);
        if (this.heap[parent][0] <= this.heap[index][0]) break;
        [this.heap[parent], this.heap[index]] = [this.heap[index], this.heap[parent]];
        index = parent;
      }
    }
    siftDown(index) {
      const length = this.heap.length;
      while (index < length) {
        const left = 2 * index + 1;
        const right = 2 * index + 2;
        let smallest = index;
        if (left < length && this.heap[left][0] < this.heap[smallest][0]) smallest = left;
        if (right < length && this.heap[right][0] < this.heap[smallest][0]) smallest = right;
        if (smallest !== index) {
          [this.heap[index], this.heap[smallest]] = [this.heap[smallest], this.heap[index]];
          index = smallest;
        } else {
          break;
        }
      }
    }
  }

  const pq = new PriorityQueue();
  pq.push([0, 0]);

  while (pq.heap.length > 0) {
    const [currentTime, u] = pq.pop();
    if (u === n - 1) return currentTime;
    if (currentTime > dist[u]) continue;
    for (const [v, s, e] of adj[u]) {
      const earliestTime = Math.max(currentTime, s);
      if (earliestTime > e) continue;
      const newTime = earliestTime + 1;
      if (newTime < dist[v]) {
        dist[v] = newTime;
        pq.push([newTime, v]);
      }
    }
  }

  return -1;
}
